#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long *A = (long long*)malloc(N * sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld", &A[i]);
        long long ops = 0;
        int i = 0, j = N-1;
        while(i < j){
            if(A[i] == A[j]){ i++; j--; }
            else if(A[i] < A[j]){ ops++; A[j] -= A[i]; i++; }
            else{ ops++; A[i] -= A[j]; j--; }
        }
        printf("%lld\n", ops);
        free(A);
    }
    return 0;
}

