int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<long long> A(N);
        for(int i=0;i<N;i++) cin>>A[i];
        long long ops = 0;
        int i=0, j=N-1;
        while(i<j){
            if(A[i]==A[j]){ ++i; --j; }
            else if(A[i] < A[j]){ ++ops; A[j]-=A[i]; ++i; }
            else{ ++ops; A[i]-=A[j]; --j; }
        }
        cout<<ops<<"\n";
    }
    return 0;
}

